// Provide deterministic writing memory for manual testing.
return [{
  json: {
    memoryId: 'memory:article-001:sample',
    feedbackId: 'feedback:article-001:sample',
    articleId: 'article-001',
    writingMemory: {
      profileVersion: '1.0.0',
      rules: [
        {
          category: 'title',
          rule: '標題優先使用問題式結構',
          evidence: ['AI Agent 不只是生成文字 → AI Agent 為什麼不能只會生成文字？'],
          confidence: 0.65
        },
        {
          category: 'cta',
          rule: 'CTA 偏向交流，不要求按讚或分享',
          evidence: ['歡迎按讚、分享與留言 → 歡迎交流你的做法'],
          confidence: 0.65
        }
      ],
      avoidPhrases: ['在這個快速變化的時代', '值得注意的是'],
      preferredPatterns: ['直接提出具體問題', '使用交流型 CTA'],
      summary: '作者偏好更直接、具體且帶問題意識的寫法。'
    },
    sourceFeedback: {
      editorialDiff: {},
      metrics: {}
    },
    metadata: {
      status: 'memory_generated'
    }
  }
}];

// Build one compact memory document for embedding and storage.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.memoryId || !body.writingMemory) {
  throw new Error('memoryId and writingMemory are required');
}
if (String(body.qdrantBaseUrl).includes('YOUR-QDRANT-CLUSTER')) {
  throw new Error('SetMemoryConfig.qdrantBaseUrl must be replaced with your Qdrant Cloud URL');
}

// Qdrant point IDs must be unsigned integers or UUIDs.
// Convert memoryId into a deterministic UUID while keeping the original memoryId in payload.
const toUuid = (value) => {
  let h1 = 0x811c9dc5;
  let h2 = 0x01000193;
  let h3 = 0x9e3779b9;
  let h4 = 0x85ebca6b;

  for (let i = 0; i < value.length; i++) {
    const code = value.charCodeAt(i);
    h1 = Math.imul(h1 ^ code, 16777619);
    h2 = Math.imul(h2 ^ code, 2246822519);
    h3 = Math.imul(h3 ^ code, 3266489917);
    h4 = Math.imul(h4 ^ code, 668265263);
  }

  const hex = (n) => (n >>> 0).toString(16).padStart(8, '0');

  const raw = `${hex(h1)}${hex(h2)}${hex(h3)}${hex(h4)}`.slice(0, 32);
  return `${raw.slice(0, 8)}-${raw.slice(8, 12)}-4${raw.slice(13, 16)}-8${raw.slice(17, 20)}-${raw.slice(20, 32)}`;
};

const rules = Array.isArray(body.writingMemory.rules)
  ? body.writingMemory.rules
  : [];

const memoryText = [
  `Summary: ${body.writingMemory.summary ?? ''}`,
  ...rules.map((rule) => `${rule.category}: ${rule.rule} (confidence ${rule.confidence})`),
  `Avoid phrases: ${(body.writingMemory.avoidPhrases ?? []).join(', ')}`,
  `Preferred patterns: ${(body.writingMemory.preferredPatterns ?? []).join(', ')}`
].filter(Boolean).join('\n');

return [{
  json: {
    original: body,
    pointId: toUuid(String(body.memoryId)),
    qdrantBaseUrl: String(body.qdrantBaseUrl).replace(/\/$/, ''),
    collection: body.collection,
    embeddingModel: body.embeddingModel,
    memoryText
  }
}];

// Attach the embedding vector to the memory document.
const response = $input.first().json;
const request = $('BuildMemoryDocument').first().json;
const vector = response.data?.[0]?.embedding;

if (!Array.isArray(vector) || vector.length === 0) {
  throw new Error('NVIDIA embedding response does not contain data[0].embedding');
}

return [{
  json: {
    ...request,
    vector
  }
}];

// Determine whether the writing memory collection exists.
const response = $input.first().json;
const request = $('AttachMemoryEmbedding').first().json;
const statusCode = response.statusCode ?? 0;

return [{
  json: {
    ...request,
    collectionExists: statusCode >= 200 && statusCode < 300
  }
}];

