// Return a compact memory update result.
const response = $input.first().json;
const request = $('AttachMemoryEmbedding').first().json;
const original = request.original;

return [{
  json: {
    ...original,
    memoryStorage: {
      provider: 'qdrant',
      collection: request.collection,
      pointId: request.pointId,
      operationStatus: response.status ?? response.result?.status ?? 'completed'
    },
    metadata: {
      ...original.metadata,
      updater: '11-style-memory-updater',
      updaterVersion: '1.1.1',
      status: 'memory_stored',
      storedAt: new Date().toISOString()
    }
  }
}];
